def mystery(x):
    if not isinstance(x, str) or len(x) != 7:
        return False
    if not x.islower() or not x.isalpha():
        return False

    # Forward polynomial rolling hash
    MOD1 = 10**9 + 7
    h1 = 0
    for c in x:
        h1 = (h1 * 31 + (ord(c) - 96)) % MOD1

    # Reverse polynomial rolling hash with different parameters
    MOD2 = 10**9 + 9
    h2 = 0
    for c in reversed(x):
        h2 = (h2 * 37 + (ord(c) - 96)) % MOD2

    return h1 == 233280566 and h2 == 44273911
